// EXPAND LIST IDS -> one item per configured list id
const cfg = $input.first().json;
let ids = cfg.CLICKUP_LIST_IDS;
if (typeof ids === 'string') { try { ids = JSON.parse(ids); } catch (e) { ids = [ids]; } }
if (!Array.isArray(ids)) ids = [ids];
ids = ids.filter(Boolean).map(id => String(id).trim());
if (ids.length === 0) throw new Error('CLICKUP_LIST_IDS is empty - set at least one list id in Set Config.');
return ids.map(id => ({ json: { list_id: id } }));

// FILTER TARGET-STATUS CANDIDATES
// Input: ALL paged responses from the parents-only fetch (subtasks=false).
const cfg = $('Set Config').first().json;
let statuses = cfg.TARGET_STATUSES;
if (typeof statuses === 'string') { try { statuses = JSON.parse(statuses); } catch (e) { statuses = [statuses]; } }
if (!Array.isArray(statuses)) statuses = [];
const targetStatuses = statuses.map(s => String(s).trim().toLowerCase());

const pages = $input.all();

// pagination truncation guard: never silently drop tickets
if (pages.length) {
  const last = pages[pages.length - 1].json || {};
  const lastTasks = (last && last.tasks) || [];
  if (lastTasks.length >= 100 && last.last_page !== true) {
    throw new Error('Pagination likely truncated: last fetched page returned ' + lastTasks.length +
      ' tasks but last_page was not true. Increase the Fetch node pagination maxRequests / check pagination config.');
  }
}

const allTasks = [];
for (const resp of pages) {
  const tasks = (resp.json && resp.json.tasks) || [];
  for (const t of tasks) allTasks.push(t);
}
console.log('Fetched ' + allTasks.length + ' parent tickets across ' + pages.length + ' page(s).');

const results = [];
for (const task of allTasks) {
  if (task.parent) continue;
  const status = ((task.status && task.status.status) || '').toLowerCase();
  if (targetStatuses.length && !targetStatuses.includes(status)) continue;
  results.push({ json: {
    task_id: task.id,
    task_name: task.name,
    status: (task.status && task.status.status) || 'unknown',
    list_id: (task.list && task.list.id) || ''
  }});
}
console.log('Target-status candidates: ' + results.length);

if (results.length === 0) {
  return [{ json: { task_id: '', task_name: 'No matching tickets found', status: 'empty', list_id: '', no_candidates: true } }];
}
return results;

// DYNAMIC BATCH LIMITER
const cfg = $('Set Config').first().json;
const MAX = Number(cfg.MAX_TICKETS_PER_RUN) || 10;
const AUTO = cfg.AUTO_ADJUST_BATCH === true || cfg.AUTO_ADJUST_BATCH === 'true';
const items = $input.all().filter(i => !i.json.no_candidates);
if (items.length === 0) return [];
const limit = AUTO ? items.length : MAX;
const batch = items.slice(0, limit);
const overflow = Math.max(0, items.length - batch.length);
console.log('Batch: processing ' + batch.length + ' of ' + items.length + ' candidate tickets (AUTO=' + AUTO + '). Overflow: ' + overflow);
return batch.map(item => ({ json: { ...item.json, total_candidates: items.length, overflow_count: overflow } }));

// EVALUATE COVERAGE (per ticket, from the task-detail response)
const detail = $input.first().json;
const cfg = $('Set Config').first().json;
const MIN_DESC = Number(cfg.MIN_DESC_LENGTH) || 100;
const TC_PREFIX = cfg.TC_PREFIX || '[TC]';
const ticket = $('Loop Each Ticket').first().json;

const subtasks = detail.subtasks || [];
const tcChildren = subtasks.filter(st => st.name && st.name.trim().startsWith(TC_PREFIX));
const hasTCs = tcChildren.length > 0;

const requirement = detail.markdown_description || detail.description || detail.text_content || '';
const isThin = requirement.trim().length < MIN_DESC;

let action = 'skip';
if (hasTCs) action = 'skip';
else if (!isThin) action = 'generate';
else action = 'monitor';

return [{ json: {
  task_id: detail.id || ticket.task_id,
  task_name: detail.name || ticket.task_name,
  status: (detail.status && detail.status.status) || ticket.status || 'unknown',
  list_id: (detail.list && detail.list.id) || ticket.list_id || '',
  requirement: requirement,
  has_tcs: hasTCs,
  existing_tc_count: tcChildren.length,
  is_thin: isThin,
  action: action,
  need_generate: action === 'generate'
}}];

// PARSE DEEPSEEK RESPONSE -> one item per test case
const response = $input.first().json;
const cfg = $('Set Config').first().json;
const TC_PREFIX = cfg.TC_PREFIX || '[TC]';
const assignee = cfg.ASSIGNEE_USER_ID || '';

let ticketData = {};
try { ticketData = $('Evaluate Coverage').first().json; }
catch (e) { ticketData = {}; }
try { if (!ticketData.task_id) ticketData = $('Loop Each Ticket').first().json; } catch (e) {}

let textContent = '';
if (response.choices && response.choices[0] && response.choices[0].message) {
  textContent = response.choices[0].message.content || '';
} else if (typeof response === 'string') {
  textContent = response;
}

let clean = textContent.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let testCases = [];
try {
  testCases = JSON.parse(clean);
} catch (e) {
  const m = clean.match(/\[[\s\S]*\]/);
  if (m) {
    try { testCases = JSON.parse(m[0]); }
    catch (e2) {
      return [{ json: { error: true, error_type: 'parse_failure', task_id: ticketData.task_id, task_name: ticketData.task_name, parse_error: e2.message, raw_preview: textContent.substring(0, 300) } }];
    }
  } else {
    return [{ json: { error: true, error_type: 'no_json_found', task_id: ticketData.task_id, task_name: ticketData.task_name, raw_preview: textContent.substring(0, 300) } }];
  }
}

if (!Array.isArray(testCases) || testCases.length === 0) {
  return [{ json: { error: true, error_type: 'empty_array', task_id: ticketData.task_id, task_name: ticketData.task_name } }];
}

return testCases.map((tc, index) => {
  const tc_id = tc.tc_id || ('TC_' + String(index + 1).padStart(3, '0'));
  const title = tc.title || 'Untitled Test Case';
  return { json: {
    tc_id: tc_id,
    title: title,
    tc_name: TC_PREFIX + ' ' + tc_id + ' - ' + title,
    type: tc.type || 'Functional - Positive',
    priority: tc.priority || 'normal',
    module: tc.module || 'General',
    objective: tc.objective || '',
    preconditions: tc.preconditions || 'None',
    steps: tc.steps || '',
    test_data: tc.test_data || 'N/A',
    expected_result: tc.expected_result || '',
    parent_task_id: ticketData.task_id,
    task_name: ticketData.task_name,
    list_id: ticketData.list_id || '',
    assignee_id: assignee,
    tc_index: index + 1,
    total_tcs: testCases.length,
    error: false
  }};
});

// ASSERT COVERAGE (verify each ticket actually got its [TC] subtasks)
const cfg = $('Set Config').first().json;
const TC_PREFIX = cfg.TC_PREFIX || '[TC]';
const MAX_RETRIES = Number(cfg.VERIFY_MAX_RETRIES);
const maxRetries = Number.isFinite(MAX_RETRIES) ? MAX_RETRIES : 2;

const detail = $input.first().json;
const generated = $('Parse TCs from DeepSeek').all().map(i => i.json).filter(t => t && t.error !== true);
if (generated.length === 0) {
  return [{ json: { coverage_ok: true, parent_task_id: (detail && detail.id) || '', note: 'no_generated_tcs' } }];
}

const parentId = generated[0].parent_task_id || (detail && detail.id) || '';
const ticketName = generated[0].task_name || (detail && detail.name) || parentId;

const existingNames = (detail.subtasks || [])
  .map(st => (st.name || '').trim())
  .filter(n => n.startsWith(TC_PREFIX));
const existingSet = new Set(existingNames);

const missing = generated.filter(tc => !existingSet.has((tc.tc_name || '').trim()));

let attempt = 0;
try { attempt = Number($json.verify_attempt) || 0; } catch (e) { attempt = 0; }

if (missing.length === 0) {
  return [{ json: { coverage_ok: true, parent_task_id: parentId, verified: existingNames.length, expected: generated.length } }];
}

if (attempt >= maxRetries) {
  throw new Error('TC coverage incomplete for "' + ticketName + '" (' + parentId + '): found ' +
    (generated.length - missing.length) + '/' + generated.length + ' after ' + attempt +
    ' retr(y/ies). Missing: ' + missing.map(m => m.tc_name).join(' | '));
}

return missing.map(tc => ({ json: { ...tc, coverage_ok: false, verify_attempt: attempt + 1 } }));
